#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    int *arr; // Pointer to store the base address of the dynamically allocated array
    long long sum = 0; // Use long long for sum to avoid potential overflow

    // Read the number of elements
    if (scanf("%d", &N) != 1 || N < 1 || N > 1000) {
        fprintf(stderr, "Invalid input for N.\n");
        return 1; // Indicate an error
    }

    // Dynamically allocate memory for N integers
    arr = (int *)malloc(N * sizeof(int));

    // Check if malloc was successful
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1; // Indicate an error
    }

    // Read N integers into the dynamically allocated array and calculate their sum
    for (int i = 0; i < N; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            fprintf(stderr, "Failed to read integer at index %d.\n", i);
            free(arr); // Free memory before exiting on error
            return 1;
        }
        sum += arr[i];
    }

    // Print the calculated sum
    printf("%lld\n", sum);

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL; // Good practice to set pointer to NULL after freeing

    return 0; // Indicate successful execution
}
